window.CRAWLER_SOURCE_FILES = {
  "shared.py": "\"\"\"Shared offline website and link utilities for crawler examples.\"\"\"\n\nimport asyncio\nfrom html.parser import HTMLParser\nimport time\nfrom urllib.parse import urldefrag, urljoin, urlparse\n\n\nHOME_URL = \"https://learn.example.com/\"\n\n# This website deliberately contains cycles, duplicates, fragments, and\n# non-crawlable links so each crawler has realistic filtering work to do.\nEXAMPLE_WEBSITE = {\n    HOME_URL: \"\"\"\n        <html><body>\n            <h1>Learn Concurrent Crawling</h1>\n            <a href=\"/tutorial\">Tutorial</a>\n            <a href=\"/reference\">Reference</a>\n            <a href=\"/tutorial#threads\">Duplicate tutorial fragment</a>\n            <a href=\"mailto:teacher@example.com\">Email the teacher</a>\n            <a href=\"https://news.example.net/story\">External news</a>\n        </body></html>\n    \"\"\",\n    \"https://learn.example.com/tutorial\": \"\"\"\n        <html><body>\n            <a href=\"/reference\">Reference</a>\n            <a href=\"/examples/basic\">Basic example</a>\n            <a href=\"/\">Back home</a>\n        </body></html>\n    \"\"\",\n    \"https://learn.example.com/reference\": \"\"\"\n        <html><body>\n            <a href=\"/examples/basic#result\">Basic example result</a>\n            <a href=\"/examples/concurrent\">Concurrent example</a>\n            <a href=\"javascript:void(0)\">Not a page</a>\n        </body></html>\n    \"\"\",\n    \"https://learn.example.com/examples/basic\": \"\"\"\n        <html><body>\n            <a href=\"/examples/concurrent\">Try concurrency next</a>\n        </body></html>\n    \"\"\",\n    \"https://learn.example.com/examples/concurrent\": \"\"\"\n        <html><body>\n            <a href=\"/tutorial\">Review the tutorial</a>\n        </body></html>\n    \"\"\",\n}\n\nPAGE_DOWNLOAD_DELAYS = {\n    HOME_URL: 0.04,\n    \"https://learn.example.com/tutorial\": 0.08,\n    \"https://learn.example.com/reference\": 0.05,\n    \"https://learn.example.com/examples/basic\": 0.03,\n    \"https://learn.example.com/examples/concurrent\": 0.06,\n}\n\n\ndef _read_example_page(url: str) -> str:\n    \"\"\"Validate a URL and return its HTML from the offline example website.\"\"\"\n    parsed_url = urlparse(url)\n    if parsed_url.scheme not in {\"http\", \"https\"}:\n        raise ConnectionError(f\"Unsupported URL scheme: {url}\")\n\n    try:\n        return EXAMPLE_WEBSITE[url]\n    except KeyError as error:\n        raise ConnectionError(f\"Page not found: {url}\") from error\n\n\ndef get_html_content(url: str) -> str:\n    \"\"\"Fetch one page through a blocking API that simulates network latency.\"\"\"\n    time.sleep(PAGE_DOWNLOAD_DELAYS.get(url, 0.02))\n    return _read_example_page(url)\n\n\nasync def get_html_content_async(url: str) -> str:\n    \"\"\"Fetch one page without blocking the asyncio event loop while waiting.\"\"\"\n    await asyncio.sleep(PAGE_DOWNLOAD_DELAYS.get(url, 0.02))\n    return _read_example_page(url)\n\n\nclass _LinkParser(HTMLParser):\n    \"\"\"Collect raw hyperlink targets from anchor elements in an HTML page.\"\"\"\n\n    def __init__(self) -> None:\n        super().__init__()\n        self.raw_links: list[str] = []\n\n    def handle_starttag(\n        self, tag: str, attributes: list[tuple[str, str | None]]\n    ) -> None:\n        if tag.lower() != \"a\":\n            return\n\n        for attribute_name, attribute_value in attributes:\n            if attribute_name.lower() == \"href\" and attribute_value:\n                self.raw_links.append(attribute_value)\n                return\n\n\ndef get_links_on_page(html_content: str, page_url: str) -> list[str]:\n    \"\"\"Extract normalized, same-site HTTP links from a downloaded HTML page.\"\"\"\n    parser = _LinkParser()\n    parser.feed(html_content)\n\n    site_host = urlparse(page_url).netloc\n    normalized_links: list[str] = []\n    seen_links: set[str] = set()\n\n    for raw_link in parser.raw_links:\n        absolute_link = urljoin(page_url, raw_link)\n        normalized_link, _fragment = urldefrag(absolute_link)\n        parsed_link = urlparse(normalized_link)\n\n        # Keep the crawl on one website and exclude mail, scripts, and similar URLs.\n        if parsed_link.scheme not in {\"http\", \"https\"}:\n            continue\n        if parsed_link.netloc != site_host:\n            continue\n\n        if normalized_link not in seen_links:\n            seen_links.add(normalized_link)\n            normalized_links.append(normalized_link)\n\n    return normalized_links\n",
  "synchronous_crawlers.py": "\"\"\"Blocking crawler examples: sequential execution and thread-pool concurrency.\"\"\"\n\nfrom collections import deque\nfrom concurrent.futures import FIRST_COMPLETED, Future, ThreadPoolExecutor, wait\nimport threading\n\nfrom shared import HOME_URL, get_html_content, get_links_on_page\n\n\nclass SequentialWebCrawler:\n    \"\"\"Crawl pages one at a time in breadth-first order.\"\"\"\n\n    def __init__(self, starting_url: str):\n        # Mark each URL as discovered when it is queued to prevent duplicates.\n        self.discovered_urls = {starting_url}\n        self.urls_to_crawl = deque([starting_url])\n        self.fetched_urls: list[str] = []\n        self.failed_urls: set[str] = set()\n\n    def crawl_page(self, url: str) -> None:\n        \"\"\"Fetch one page and queue links that have not been discovered before.\"\"\"\n        try:\n            html_content = get_html_content(url)\n        except ConnectionError:\n            self.failed_urls.add(url)\n            return\n\n        self.fetched_urls.append(url)\n        for link in get_links_on_page(html_content, url):\n            if link not in self.discovered_urls:\n                self.discovered_urls.add(link)\n                self.urls_to_crawl.append(link)\n\n    def run(self) -> list[str]:\n        \"\"\"Crawl until every discovered page has been handled.\"\"\"\n        while self.urls_to_crawl:\n            current_url = self.urls_to_crawl.popleft()\n            self.crawl_page(current_url)\n\n        return self.fetched_urls.copy()\n\n\nclass ThreadPoolWebCrawler:\n    \"\"\"Crawl blocking page requests concurrently by using worker threads.\"\"\"\n\n    def __init__(self, starting_url: str, max_workers: int = 20):\n        if max_workers < 1:\n            raise ValueError(\"max_workers must be at least 1\")\n\n        self.discovered_urls = {starting_url}\n        self.urls_to_crawl = deque([starting_url])\n        self.state_lock = threading.Lock()\n        self.pending_futures: set[Future[None]] = set()\n        self.fetched_urls: list[str] = []\n        self.failed_urls: set[str] = set()\n        self.max_workers = max_workers\n\n    def crawl_page(self, url: str) -> None:\n        \"\"\"Fetch one page, then atomically deduplicate and queue its links.\"\"\"\n        try:\n            html_content = get_html_content(url)\n        except ConnectionError:\n            with self.state_lock:\n                self.failed_urls.add(url)\n            return\n\n        discovered_links = get_links_on_page(html_content, url)\n        with self.state_lock:\n            self.fetched_urls.append(url)\n            # The check-and-enqueue sequence must not race with another thread.\n            for link in discovered_links:\n                if link not in self.discovered_urls:\n                    self.discovered_urls.add(link)\n                    self.urls_to_crawl.append(link)\n\n    def run(self) -> list[str]:\n        \"\"\"Keep a bounded set of page requests in flight until crawling ends.\"\"\"\n        with ThreadPoolExecutor(max_workers=self.max_workers) as thread_pool:\n            while True:\n                with self.state_lock:\n                    available_worker_slots = (\n                        self.max_workers - len(self.pending_futures)\n                    )\n                    pages_to_submit = min(\n                        available_worker_slots, len(self.urls_to_crawl)\n                    )\n\n                    for _ in range(pages_to_submit):\n                        url = self.urls_to_crawl.popleft()\n                        future = thread_pool.submit(self.crawl_page, url)\n                        self.pending_futures.add(future)\n\n                    # In-flight pages can discover more URLs, so both states\n                    # must be empty before it is safe to terminate the crawl.\n                    if not self.urls_to_crawl and not self.pending_futures:\n                        break\n\n                # Wait for real progress rather than polling worker completion.\n                done_futures, pending_futures = wait(\n                    self.pending_futures,\n                    return_when=FIRST_COMPLETED,\n                )\n\n                for future in done_futures:\n                    # result() re-raises unexpected failures from worker threads.\n                    future.result()\n\n                self.pending_futures = pending_futures\n\n        return self.fetched_urls.copy()\n\n\nif __name__ == \"__main__\":\n    sequential_pages = SequentialWebCrawler(HOME_URL).run()\n    thread_pool_pages = ThreadPoolWebCrawler(HOME_URL).run()\n\n    print(\"Sequential crawl order:\", sequential_pages)\n    print(\"Thread-pool fetched pages:\", sorted(thread_pool_pages))\n",
  "async_crawler.py": "\"\"\"Asyncio crawler example that coordinates non-blocking page requests.\"\"\"\n\nimport asyncio\nfrom collections import deque\n\nfrom shared import HOME_URL, get_html_content_async, get_links_on_page\n\n\nclass AsyncWebCrawler:\n    \"\"\"Crawl pages concurrently with asyncio tasks on one event loop thread.\"\"\"\n\n    def __init__(self, starting_url: str, max_concurrency: int = 20):\n        if max_concurrency < 1:\n            raise ValueError(\"max_concurrency must be at least 1\")\n\n        self.discovered_urls = {starting_url}\n        self.urls_to_crawl = deque([starting_url])\n        self.fetched_urls: list[str] = []\n        self.failed_urls: set[str] = set()\n        self.max_concurrency = max_concurrency\n\n    async def fetch_links(self, url: str) -> tuple[str, list[str] | None]:\n        \"\"\"Fetch one page and return its URL plus links, or a failed marker.\"\"\"\n        try:\n            html_content = await get_html_content_async(url)\n        except ConnectionError:\n            return url, None\n\n        return url, get_links_on_page(html_content, url)\n\n    async def run(self) -> list[str]:\n        \"\"\"Schedule bounded async tasks until no queued or running work remains.\"\"\"\n        pending_tasks: set[asyncio.Task[tuple[str, list[str] | None]]] = set()\n\n        while self.urls_to_crawl or pending_tasks:\n            available_task_slots = self.max_concurrency - len(pending_tasks)\n            pages_to_schedule = min(\n                available_task_slots, len(self.urls_to_crawl)\n            )\n\n            for _ in range(pages_to_schedule):\n                url = self.urls_to_crawl.popleft()\n                task = asyncio.create_task(self.fetch_links(url))\n                pending_tasks.add(task)\n\n            # At least one task is present here because the loop has work left.\n            done_tasks, pending_tasks = await asyncio.wait(\n                pending_tasks,\n                return_when=asyncio.FIRST_COMPLETED,\n            )\n\n            for task in done_tasks:\n                # task.result() also re-raises unexpected coroutine failures.\n                url, discovered_links = task.result()\n                if discovered_links is None:\n                    self.failed_urls.add(url)\n                    continue\n\n                self.fetched_urls.append(url)\n                for link in discovered_links:\n                    if link not in self.discovered_urls:\n                        self.discovered_urls.add(link)\n                        self.urls_to_crawl.append(link)\n\n        return self.fetched_urls.copy()\n\n\nasync def main() -> None:\n    \"\"\"Run the async crawler from the command line.\"\"\"\n    crawler = AsyncWebCrawler(HOME_URL)\n    pages = await crawler.run()\n    print(\"Asyncio crawl:\", sorted(pages))\n\n\nif __name__ == \"__main__\":\n    asyncio.run(main())\n",
  "compare_examples.py": "\"\"\"Run all crawler implementations against the same offline website.\"\"\"\n\nimport asyncio\nfrom collections.abc import Callable\nfrom time import perf_counter\n\nfrom async_crawler import AsyncWebCrawler\nfrom shared import HOME_URL\nfrom synchronous_crawlers import SequentialWebCrawler, ThreadPoolWebCrawler\n\n\ndef measure_run(label: str, crawler_run: Callable[[], list[str]]) -> list[str]:\n    \"\"\"Run a blocking crawler and print its elapsed time and discovered pages.\"\"\"\n    started_at = perf_counter()\n    pages = crawler_run()\n    elapsed_seconds = perf_counter() - started_at\n    print(f\"{label:<12} {elapsed_seconds:.3f}s  {len(pages)} pages\")\n    return pages\n\n\nasync def measure_async_run() -> list[str]:\n    \"\"\"Run the async crawler and print its elapsed time and discovered pages.\"\"\"\n    started_at = perf_counter()\n    pages = await AsyncWebCrawler(HOME_URL, max_concurrency=2).run()\n    elapsed_seconds = perf_counter() - started_at\n    print(f\"{'Asyncio':<12} {elapsed_seconds:.3f}s  {len(pages)} pages\")\n    return pages\n\n\nasync def main() -> None:\n    \"\"\"Compare the crawler styles under the same simulated network delays.\"\"\"\n    print(\"Crawler       Time    Result\")\n    print(\"----------------------------\")\n    sequential_pages = measure_run(\n        \"Sequential\",\n        lambda: SequentialWebCrawler(HOME_URL).run(),\n    )\n    thread_pool_pages = measure_run(\n        \"Thread pool\",\n        lambda: ThreadPoolWebCrawler(HOME_URL, max_workers=2).run(),\n    )\n    async_pages = await measure_async_run()\n\n    all_crawlers_found_same_pages = (\n        set(sequential_pages) == set(thread_pool_pages) == set(async_pages)\n    )\n    print(f\"Same pages:   {all_crawlers_found_same_pages}\")\n\n\nif __name__ == \"__main__\":\n    asyncio.run(main())\n",
  "lessons/lesson_timeout.py": "\"\"\"Lesson: protect an asynchronous fetch with a timeout.\"\"\"\n\nimport asyncio\n\nfrom shared import HOME_URL, get_html_content_async\n\n\nasync def fetch_with_timeout(url: str, timeout_seconds: float) -> str | None:\n    \"\"\"Return page HTML, or None when the request exceeds its time budget.\"\"\"\n    try:\n        return await asyncio.wait_for(\n            get_html_content_async(url),\n            timeout=timeout_seconds,\n        )\n    except asyncio.TimeoutError:\n        return None\n\n\nasync def main() -> None:\n    \"\"\"Show one timed-out request and one successful request.\"\"\"\n    timed_out_html = await fetch_with_timeout(HOME_URL, timeout_seconds=0.01)\n    successful_html = await fetch_with_timeout(HOME_URL, timeout_seconds=0.10)\n\n    print(\"Short timeout failed:\", timed_out_html is None)\n    print(\"Long timeout succeeded:\", successful_html is not None)\n\n\nif __name__ == \"__main__\":\n    asyncio.run(main())\n",
  "lessons/lesson_retry.py": "\"\"\"Lesson: retry temporary failures with bounded exponential backoff.\"\"\"\n\nimport asyncio\nfrom collections.abc import Awaitable, Callable\n\n\nclass TemporaryFetchError(ConnectionError):\n    \"\"\"Represent a request failure that may succeed when tried again.\"\"\"\n\n\nclass FlakyPageFetcher:\n    \"\"\"Fail a configured number of times before returning page HTML.\"\"\"\n\n    def __init__(self, failures_before_success: int):\n        self.failures_remaining = failures_before_success\n        self.attempts = 0\n\n    async def fetch(self, url: str) -> str:\n        \"\"\"Fetch one page after simulating temporary failures.\"\"\"\n        self.attempts += 1\n        if self.failures_remaining > 0:\n            self.failures_remaining -= 1\n            raise TemporaryFetchError(f\"Temporary failure for {url}\")\n        return f\"<html>Fetched {url}</html>\"\n\n\nasync def fetch_with_retry(\n    fetch: Callable[[str], Awaitable[str]],\n    url: str,\n    max_attempts: int = 3,\n    base_delay_seconds: float = 0.01,\n) -> str:\n    \"\"\"Retry temporary failures with a short exponentially increasing delay.\"\"\"\n    if max_attempts < 1:\n        raise ValueError(\"max_attempts must be at least 1\")\n\n    for attempt_number in range(1, max_attempts + 1):\n        try:\n            return await fetch(url)\n        except TemporaryFetchError:\n            if attempt_number == max_attempts:\n                raise\n\n            delay_seconds = base_delay_seconds * (2 ** (attempt_number - 1))\n            await asyncio.sleep(delay_seconds)\n\nasync def main() -> None:\n    \"\"\"Show a temporary failure recovering within the retry budget.\"\"\"\n    fetcher = FlakyPageFetcher(failures_before_success=2)\n    html_content = await fetch_with_retry(fetcher.fetch, \"https://learn.example.com/\")\n\n    print(\"Request succeeded:\", \"Fetched\" in html_content)\n    print(\"Attempts used:\", fetcher.attempts)\n\n\nif __name__ == \"__main__\":\n    asyncio.run(main())\n",
  "lessons/lesson_semaphore.py": "\"\"\"Lesson: limit active asynchronous requests with a semaphore.\"\"\"\n\nimport asyncio\n\n\nclass RequestCounter:\n    \"\"\"Record current and maximum simultaneous simulated requests.\"\"\"\n\n    def __init__(self) -> None:\n        self.active_requests = 0\n        self.maximum_active_requests = 0\n\n    async def fetch(self, url: str, semaphore: asyncio.Semaphore) -> str:\n        \"\"\"Fetch one simulated page only after acquiring a concurrency slot.\"\"\"\n        async with semaphore:\n            self.active_requests += 1\n            self.maximum_active_requests = max(\n                self.maximum_active_requests,\n                self.active_requests,\n            )\n            try:\n                await asyncio.sleep(0.02)\n                return url\n            finally:\n                self.active_requests -= 1\n\n\nasync def measure_limited_concurrency(urls: list[str], limit: int) -> int:\n    \"\"\"Fetch every URL and return the highest observed active request count.\"\"\"\n    if limit < 1:\n        raise ValueError(\"limit must be at least 1\")\n\n    semaphore = asyncio.Semaphore(limit)\n    counter = RequestCounter()\n    await asyncio.gather(*(counter.fetch(url, semaphore) for url in urls))\n    return counter.maximum_active_requests\n\n\nasync def main() -> None:\n    \"\"\"Show that many scheduled tasks can obey a smaller active limit.\"\"\"\n    urls = [f\"https://learn.example.com/page/{number}\" for number in range(6)]\n    observed_maximum = await measure_limited_concurrency(urls, limit=2)\n    print(\"Tasks scheduled:\", len(urls))\n    print(\"Maximum active requests:\", observed_maximum)\n\n\nif __name__ == \"__main__\":\n    asyncio.run(main())\n",
  "lessons/lesson_cancellation.py": "\"\"\"Lesson: cancel pending tasks and wait for their cleanup.\"\"\"\n\nimport asyncio\n\n\nasync def fetch_page(name: str, delay_seconds: float) -> str:\n    \"\"\"Return a page name after a simulated network delay.\"\"\"\n    await asyncio.sleep(delay_seconds)\n    return name\n\n\nasync def cancel_after_first_completion(\n    request_delays: dict[str, float],\n) -> tuple[set[str], set[str]]:\n    \"\"\"Keep the first completed results and cancel all slower requests.\"\"\"\n    if not request_delays:\n        return set(), set()\n\n    tasks = {\n        asyncio.create_task(fetch_page(name, delay_seconds)): name\n        for name, delay_seconds in request_delays.items()\n    }\n\n    done_tasks, pending_tasks = await asyncio.wait(\n        tasks,\n        return_when=asyncio.FIRST_COMPLETED,\n    )\n    completed_names = {task.result() for task in done_tasks}\n\n    tasks_to_cancel = list(pending_tasks)\n    for task in tasks_to_cancel:\n        task.cancel()\n\n    cancellation_results = await asyncio.gather(\n        *tasks_to_cancel,\n        return_exceptions=True,\n    )\n    cancelled_names = {\n        tasks[task]\n        for task, result in zip(tasks_to_cancel, cancellation_results)\n        if isinstance(result, asyncio.CancelledError)\n    }\n    return completed_names, cancelled_names\n\n\nasync def main() -> None:\n    \"\"\"Show that slow requests are explicitly cancelled and collected.\"\"\"\n    completed, cancelled = await cancel_after_first_completion(\n        {\"fast-page\": 0.01, \"slow-page-a\": 0.10, \"slow-page-b\": 0.12}\n    )\n    print(\"Completed:\", sorted(completed))\n    print(\"Cancelled:\", sorted(cancelled))\n\n\nif __name__ == \"__main__\":\n    asyncio.run(main())\n"
};
